// DataSet 이벤트
//-------------------------------------------------------------------------
scwin.ds_vesselInfoList_onrowpositionchange = function (info) {
	if (info.newRowIndex > -1) {	
        scwin.f_Create();
		scwin.f_RetrieveVesselEdiateTrustList(ds_vesselInfoList.getRowPosition());	// 알선수탁내역 조회
	}	
};

//-------------------------------------------------------------------------
// 그리드 이벤트
//-------------------------------------------------------------------------
// 선박정보 cellClick
scwin.gr_vesselInfoList_oncellclick = async function (rowIndex, columnIndex, columnId) {
	// 전표번호 선택 시
    if (columnId == "setoffSlipNo" && !$c.gus.cfIsNull(ds_vesselInfoList.getCellData(rowIndex, "setoffSlipNo"))) {
        await $c.gus.cfShowSlipInfo(ds_vesselInfoList.getCellData(rowIndex, "setoffSlipNo"));
    } else if (columnId == "recvSetoffSlipNo" && !$c.gus.cfIsNull(ds_vesselInfoList.getCellData(rowIndex, "recvSetoffSlipNo"))) {
    	await $c.gus.cfShowSlipInfo(ds_vesselInfoList.getCellData(rowIndex, "recvSetoffSlipNo"));
    }

    if (!$c.gus.cfIsNull(ds_vesselInfoList.getCellData(rowIndex, columnId))) {
    	if (columnId == "setoffSlipNo") {
            ed_slipNo.setValue(ds_vesselInfoList.getCellData(rowIndex,"setoffSlipNo"));
			scwin.f_openPopUp('4', ed_slipNo.getValue(), scwin.hdn_slipNo, 'T');
	   		scwin.chk = true;
			scwin.f_slipRetrieve();
			scwin.chk = false;

			$c.gus.cfEnableObjects([btn_new, btn_delete]);
			$c.gus.cfDisableObjects([btn_create, btn_setoff, btn_bond]);
    	} else {
	    	ed_slipNo.setValue(ds_vesselInfoList.getCellData(rowIndex, "recvSetoffSlipNo"));
			scwin.f_openPopUp('5', ed_slipNo.getValue(), scwin.hdn_slipNo, 'T');
	   		scwin.chk = true;
			scwin.f_slipRetrieve();
			scwin.chk = false;

			$c.gus.cfEnableObjects([btn_create, btn_setoff])
			$c.gus.cfDisableObjects([btn_bond, btn_delete, btn_new])      	
    	}

    } else {
	    $c.gus.cfEnableObjects([btn_bond, btn_create])
		$c.gus.cfDisableObjects([btn_setoff, btn_delete, btn_new])
    }

    scwin.hdn_slipNo = '';
};

